 10→ * Loading strategy:
 11→ * 1. Custom installer files (github-copilot.js, kilo.js, rovodev.js) - for platforms with unique installation logic
 12→ * 2. Config-driven handlers (from platform-codes.yaml) - for standard IDE installation patterns
 13→ */
 14→class IdeManager {
 15→  constructor() {
 16→    this.handlers = new Map();
 17→    this._initialized = false;
 18→    this.bmadFolderName = BMAD_FOLDER_NAME; // Default, can be overridden
 19→  }
 20→
 21→  /**
 22→   * Set the bmad folder name for all IDE handlers
 23→   * @param {string} bmadFolderName - The bmad folder name
 24→   */
 25→  setBmadFolderName(bmadFolderName) {
 26→    this.bmadFolderName = bmadFolderName;
 27→    // Update all loaded handlers
 28→    for (const handler of this.handlers.values()) {
 29→      if (typeof handler.setBmadFolderName === 'function') {
 30→        handler.setBmadFolderName(bmadFolderName);
 31→      }
 32→    }
 33→  }
 34→
 35→  /**
 36→   * Ensure handlers are loaded (lazy loading)
 37→   */
 38→  async ensureInitialized() {
 39→    if (!this._initialized) {
 40→      await this.loadHandlers();
 41→      this._initialized = true;
 42→    }
 43→  }
 44→
 45→  /**
 46→   * Dynamically load all IDE handlers
 47→   * 1. Load custom installer files first (github-copilot.js, kilo.js, rovodev.js)
 48→   * 2. Load config-driven handlers from platform-codes.yaml
 49→   */
 50→  async loadHandlers() {
 51→    // Load custom installer files
 52→    await this.loadCustomInstallerFiles();
 53→
 54→    // Load config-driven handlers from platform-codes.yaml
 55→    await this.loadConfigDrivenHandlers();
 56→  }
 57→
 58→  /**
 59→   * Load custom installer files (unique installation logic)
 60→   * These files have special installation patterns that don't fit the config-driven model
 61→   * Note: codex was migrated to config-driven (platform-codes.yaml) and no longer needs a custom installer
 62→   */
 63→  async loadCustomInstallerFiles() {
 64→    const ideDir = __dirname;
 65→    const customFiles = ['github-copilot.js', 'kilo.js', 'rovodev.js'];
 66→
 67→    for (const file of customFiles) {
 68→      const filePath = path.join(ideDir, file);
 69→      if (!fs.existsSync(filePath)) continue;
 70→
 71→      try {
 72→        const HandlerModule = require(filePath);
 73→        const HandlerClass = HandlerModule.default || Object.values(HandlerModule)[0];
 74→
 75→        if (HandlerClass) {
 76→          const instance = new HandlerClass();
 77→          if (instance.name && typeof instance.name === 'string') {
 78→            if (typeof instance.setBmadFolderName === 'function') {
 79→              instance.setBmadFolderName(this.bmadFolderName);
 80→            }
 81→            this.handlers.set(instance.name, instance);
 82→          }
 83→        }
 84→      } catch (error) {
 85→        await prompts.log.warn(`Warning: Could not load ${file}: ${error.message}`);
 86→      }
 87→    }
 88→  }
 89→
 90→  /**
 91→   * Load config-driven handlers from platform-codes.yaml
 92→   * This creates ConfigDrivenIdeSetup instances for platforms with installer config
 93→   */
 94→  async loadConfigDrivenHandlers() {
 95→    const { loadPlatformCodes } = require('./platform-codes');
 96→    const platformConfig = await loadPlatformCodes();
 97→
 98→    const { ConfigDrivenIdeSetup } = require('./_config-driven');
 99→
100→    for (const [platformCode, platformInfo] of Object.entries(platformConfig.platforms)) {
101→      // Skip if already loaded by custom installer
102→      if (this.handlers.has(platformCode)) continue;
103→
104→      // Skip if no installer config (platform may not need installation)
105→      if (!platformInfo.installer) continue;
106→
107→      const handler = new ConfigDrivenIdeSetup(platformCode, platformInfo);
108→      if (typeof handler.setBmadFolderName === 'function') {
109→        handler.setBmadFolderName(this.bmadFolderName);
110→      }
111→      this.handlers.set(platformCode, handler);
112→    }
113→  }
114→
115→  /**
116→   * Get all available IDEs with their metadata
117→   * @returns {Array} Array of IDE information objects
118→   */
119→  getAvailableIdes() {
120→    const ides = [];
121→
122→    for (const [key, handler] of this.handlers) {
123→      // Skip handlers without valid names
124→      const name = handler.displayName || handler.name || key;
125→
126→      // Filter out invalid entries (undefined name, empty key, etc.)
127→      if (!key || !name || typeof key !== 'string' || typeof name !== 'string') {
128→        continue;
129→      }
130→
131→      ides.push({
132→        value: key,
133→        name: name,
134→        preferred: handler.preferred || false,
135→      });
136→    }
137→
138→    // Sort: preferred first, then alphabetical
139→    ides.sort((a, b) => {
140→      if (a.preferred && !b.preferred) return -1;
141→      if (!a.preferred && b.preferred) return 1;
142→      return a.name.localeCompare(b.name);
143→    });
144→
145→    return ides;
146→  }
147→
148→  /**
149→   * Get preferred IDEs
150→   * @returns {Array} Array of preferred IDE information
151→   */
152→  getPreferredIdes() {
153→    return this.getAvailableIdes().filter((ide) => ide.preferred);
154→  }
155→
156→  /**
157→   * Get non-preferred IDEs
158→   * @returns {Array} Array of non-preferred IDE information
159→   */
160→  getOtherIdes() {
161→    return this.getAvailableIdes().filter((ide) => !ide.preferred);
162→  }
163→
164→  /**
165→   * Setup IDE configuration
166→   * @param {string} ideName - Name of the IDE
167→   * @param {string} projectDir - Project directory
168→   * @param {string} bmadDir - BMAD installation directory
169→   * @param {Object} options - Setup options
170→   */
171→  async setup(ideName, projectDir, bmadDir, options = {}) {
172→    const handler = this.handlers.get(ideName.toLowerCase());
173→
174→    if (!handler) {
175→      await prompts.log.warn(`IDE '${ideName}' is not yet supported`);
176→      await prompts.log.message(`Supported IDEs: ${[...this.handlers.keys()].join(', ')}`);
177→      return { success: false, ide: ideName, error: 'unsupported IDE' };
178→    }
179→
180→    try {
181→      const handlerResult = await handler.setup(projectDir, bmadDir, options);
182→      // Build detail string from handler-returned data
183→      let detail = '';
184→      if (handlerResult && handlerResult.results) {
185→        // Config-driven handlers return { success, results: { agents, workflows, tasks, tools } }
186→        const r = handlerResult.results;
187→        const parts = [];
188→        if (r.agents > 0) parts.push(`${r.agents} agents`);
189→        if (r.workflows > 0) parts.push(`${r.workflows} workflows`);
190→        if (r.tasks > 0) parts.push(`${r.tasks} tasks`);
191→        if (r.tools > 0) parts.push(`${r.tools} tools`);
192→        detail = parts.join(', ');
193→      } else if (handlerResult && handlerResult.modes !== undefined) {
194→        // Kilo handler returns { success, modes, workflows, tasks, tools }
195→        const parts = [];
196→        if (handlerResult.modes > 0) parts.push(`${handlerResult.modes} modes`);
197→        if (handlerResult.workflows > 0) parts.push(`${handlerResult.workflows} workflows`);
198→        if (handlerResult.tasks > 0) parts.push(`${handlerResult.tasks} tasks`);
199→        if (handlerResult.tools > 0) parts.push(`${handlerResult.tools} tools`);
200→        detail = parts.join(', ');
201→      }
202→      // Propagate handler's success status (default true for backward compat)
203→      const success = handlerResult?.success !== false;
204→      return { success, ide: ideName, detail, error: handlerResult?.error, handlerResult };
205→    } catch (error) {
206→      await prompts.log.error(`Failed to setup ${ideName}: ${error.message}`);
207→      return { success: false, ide: ideName, error: error.message };
208→    }
209→  }
210→
211→  /**
212→   * Cleanup IDE configurations
213→   * @param {string} projectDir - Project directory
214→   * @param {Object} [options] - Cleanup options passed through to handlers
215→   */
216→  async cleanup(projectDir, options = {}) {
217→    const results = [];
218→
219→    for (const [name, handler] of this.handlers) {
220→      try {
221→        await handler.cleanup(projectDir, options);
222→        results.push({ ide: name, success: true });
223→      } catch (error) {
224→        results.push({ ide: name, success: false, error: error.message });
225→      }
226→    }
227→
228→    return results;
229→  }
230→
231→  /**
232→   * Cleanup only the IDEs in the provided list
233→   * Falls back to cleanup() (all handlers) if ideList is empty or undefined
234→   * @param {string} projectDir - Project directory
235→   * @param {Array<string>} ideList - List of IDE names to clean up
236→   * @param {Object} [options] - Cleanup options passed through to handlers
237→   * @returns {Array} Results array
238→   */
239→  async cleanupByList(projectDir, ideList, options = {}) {
240→    if (!ideList || ideList.length === 0) {
241→      return this.cleanup(projectDir, options);
242→    }
243→
244→    await this.ensureInitialized();
245→    const results = [];
246→
247→    // Build lowercase lookup for case-insensitive matching
248→    const lowercaseHandlers = new Map([...this.handlers.entries()].map(([k, v]) => [k.toLowerCase(), v]));
249→
250→    for (const ideName of ideList) {
251→      const handler = lowercaseHandlers.get(ideName.toLowerCase());
252→      if (!handler) continue;
253→
254→      try {
255→        await handler.cleanup(projectDir, options);
256→        results.push({ ide: ideName, success: true });
257→      } catch (error) {
258→        results.push({ ide: ideName, success: false, error: error.message });
259→      }
260→    }
261→
262→    return results;
263→  }
264→
265→  /**
266→   * Get list of supported IDEs
267→   * @returns {Array} List of supported IDE names
