128→      const coreAgents = await this.scanDirectory(coreAgentsPath, '.md');
129→      agents.push(
130→        ...coreAgents.map((a) => ({
131→          ...a,
132→          module: 'core',
133→        })),
134→      );
135→    }
136→
137→    // Get module agents
138→    const entries = await fs.readdir(bmadDir, { withFileTypes: true });
139→    for (const entry of entries) {
140→      if (entry.isDirectory() && entry.name !== 'core' && entry.name !== '_config' && entry.name !== 'agents') {
141→        const moduleAgentsPath = path.join(bmadDir, entry.name, 'agents');
142→        if (await fs.pathExists(moduleAgentsPath)) {
143→          const moduleAgents = await this.scanDirectory(moduleAgentsPath, '.md');
144→          agents.push(
145→            ...moduleAgents.map((a) => ({
146→              ...a,
147→              module: entry.name,
148→            })),
149→          );
150→        }
151→      }
152→    }
153→
154→    // Get standalone agents from bmad/agents/ directory
155→    const standaloneAgentsDir = path.join(bmadDir, 'agents');
156→    if (await fs.pathExists(standaloneAgentsDir)) {
157→      const agentDirs = await fs.readdir(standaloneAgentsDir, { withFileTypes: true });
158→
159→      for (const agentDir of agentDirs) {
160→        if (!agentDir.isDirectory()) continue;
161→
162→        const agentDirPath = path.join(standaloneAgentsDir, agentDir.name);
163→        const agentFiles = await fs.readdir(agentDirPath);
164→
165→        for (const file of agentFiles) {
166→          if (!file.endsWith('.md')) continue;
167→          if (file.includes('.customize.')) continue;
168→
169→          const filePath = path.join(agentDirPath, file);
170→          const content = await fs.readFile(filePath, 'utf8');
171→
172→          if (content.includes('localskip="true"')) continue;
173→
174→          agents.push({
175→            name: file.replace('.md', ''),
176→            path: filePath,
177→            relativePath: path.relative(standaloneAgentsDir, filePath),
178→            filename: file,
179→            module: 'standalone', // Mark as standalone agent
180→          });
181→        }
182→      }
183→    }
184→
185→    return agents;
186→  }
