375→  /**
376→   * Scan a directory for files with specific extension(s)
377→   * @param {string} dir - Directory to scan
378→   * @param {string|Array<string>} ext - File extension(s) to match (e.g., '.md' or ['.md', '.xml'])
379→   * @returns {Array} List of file info objects
380→   */
381→  async scanDirectory(dir, ext) {
382→    const files = [];
383→
384→    if (!(await fs.pathExists(dir))) {
385→      return files;
386→    }
387→
388→    // Normalize ext to array
389→    const extensions = Array.isArray(ext) ? ext : [ext];
390→
391→    const entries = await fs.readdir(dir, { withFileTypes: true });
392→
393→    for (const entry of entries) {
394→      const fullPath = path.join(dir, entry.name);
395→
396→      if (entry.isDirectory()) {
397→        // Recursively scan subdirectories
398→        const subFiles = await this.scanDirectory(fullPath, ext);
399→        files.push(...subFiles);
400→      } else if (entry.isFile()) {
401→        // Check if file matches any of the extensions
402→        const matchedExt = extensions.find((e) => entry.name.endsWith(e));
403→        if (matchedExt) {
404→          files.push({
405→            name: path.basename(entry.name, matchedExt),
406→            path: fullPath,
407→            relativePath: path.relative(dir, fullPath),
408→            filename: entry.name,
409→          });
410→        }
411→      }
412→    }
413→
414→    return files;
415→  }
