417→  /**
418→   * Scan a directory for files with specific extension(s) and check standalone attribute
419→   * @param {string} dir - Directory to scan
420→   * @param {string|Array<string>} ext - File extension(s) to match (e.g., '.md' or ['.md', '.xml'])
421→   * @returns {Array} List of file info objects with standalone property
422→   */
423→  async scanDirectoryWithStandalone(dir, ext) {
424→    const files = [];
425→
426→    if (!(await fs.pathExists(dir))) {
427→      return files;
428→    }
429→
430→    // Normalize ext to array
431→    const extensions = Array.isArray(ext) ? ext : [ext];
432→
433→    const entries = await fs.readdir(dir, { withFileTypes: true });
434→
435→    for (const entry of entries) {
436→      const fullPath = path.join(dir, entry.name);
437→
438→      if (entry.isDirectory()) {
439→        // Recursively scan subdirectories
440→        const subFiles = await this.scanDirectoryWithStandalone(fullPath, ext);
441→        files.push(...subFiles);
442→      } else if (entry.isFile()) {
443→        // Check if file matches any of the extensions
444→        const matchedExt = extensions.find((e) => entry.name.endsWith(e));
445→        if (matchedExt) {
446→          // Read file content to check for standalone attribute
447→          // All non-internal files are considered standalone by default
448→          let standalone = true;
449→          try {
450→            const content = await fs.readFile(fullPath, 'utf8');
451→
452→            // Skip internal/engine files (not user-facing)
453→            if (content.includes('internal="true"')) {
454→              continue;
455→            }
456→
457→            // Check for explicit standalone: false
458→            if (entry.name.endsWith('.xml')) {
459→              // For XML files, check for standalone="false" attribute
460→              const tagMatch = content.match(/<(task|tool)[^>]*standalone="false"/);
461→              standalone = !tagMatch;
462→            } else if (entry.name.endsWith('.md')) {
463→              // For MD files, parse YAML frontmatter
464→              const frontmatterMatch = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
465→              if (frontmatterMatch) {
466→                try {
467→                  const yaml = require('yaml');
468→                  const frontmatter = yaml.parse(frontmatterMatch[1]);
469→                  standalone = frontmatter.standalone !== false && frontmatter.standalone !== 'false';
470→                } catch {
471→                  // If YAML parsing fails, default to standalone
472→                }
473→              }
474→              // No frontmatter means standalone (default)
475→            }
476→          } catch {
477→            // If we can't read the file, default to standalone
478→            standalone = true;
479→          }
480→
481→          files.push({
482→            name: path.basename(entry.name, matchedExt),
483→            path: fullPath,
484→            relativePath: path.relative(dir, fullPath),
485→            filename: entry.name,
486→            standalone: standalone,
487→          });
488→        }
489→      }
490→    }
491→
492→    return files;
493→  }
