495→  /**
496→   * Create IDE command/rule file from agent or task
497→   * @param {string} content - File content
498→   * @param {Object} metadata - File metadata
499→   * @param {string} projectDir - The actual project directory path
500→   * @returns {string} Processed content
501→   */
502→  processContent(content, metadata = {}, projectDir = null) {
503→    // Replace placeholders
504→    let processed = content;
505→
506→    // Inject activation block for agent files FIRST (before replacements)
507→    if (metadata.name && content.includes('<agent')) {
508→      processed = this.xmlHandler.injectActivationSimple(processed, metadata);
509→    }
510→
511→    // Only replace {project-root} if a specific projectDir is provided
512→    // Otherwise leave the placeholder intact
513→    // Note: Don't add trailing slash - paths in source include leading slash
514→    if (projectDir) {
515→      processed = processed.replaceAll('{project-root}', projectDir);
516→    }
517→    processed = processed.replaceAll('{module}', metadata.module || 'core');
518→    processed = processed.replaceAll('{agent}', metadata.name || '');
519→    processed = processed.replaceAll('{task}', metadata.name || '');
520→
521→    return processed;
522→  }
