551→  /**
552→   * Copy file from source to destination (replaces _bmad placeholder in text files)
553→   * @param {string} source - Source file path
554→   * @param {string} dest - Destination file path
555→   */
556→  async copyFile(source, dest) {
557→    // List of text file extensions that should have placeholder replacement
558→    const textExtensions = ['.md', '.yaml', '.yml', '.txt', '.json', '.js', '.ts', '.html', '.css', '.sh', '.bat', '.csv'];
559→    const ext = path.extname(source).toLowerCase();
560→
561→    await this.ensureDir(path.dirname(dest));
562→
563→    // Check if this is a text file that might contain placeholders
564→    if (textExtensions.includes(ext)) {
565→      try {
566→        // Read the file content
567→        let content = await fs.readFile(source, 'utf8');
568→
569→        // Replace _bmad placeholder with actual folder name
570→        if (content.includes('_bmad')) {
571→          content = content.replaceAll('_bmad', this.bmadFolderName);
572→        }
573→
574→        // Replace escape sequence _bmad with literal _bmad
575→        if (content.includes('_bmad')) {
576→          content = content.replaceAll('_bmad', '_bmad');
577→        }
578→
579→        // Write to dest with replaced content
580→        await fs.writeFile(dest, content, 'utf8');
581→      } catch {
582→        // If reading as text fails, fall back to regular copy
583→        await fs.copy(source, dest, { overwrite: true });
584→      }
585→    } else {
586→      // Binary file or other file type - just copy directly
587→      await fs.copy(source, dest, { overwrite: true });
588→    }
589→  }
