 11→/**
 12→ * Config-driven IDE setup handler
 13→ *
 14→ * This class provides a standardized way to install BMAD artifacts to IDEs
 15→ * based on configuration in platform-codes.yaml. It eliminates the need for
 16→ * individual installer files for each IDE.
 17→ *
 18→ * Features:
 19→ * - Config-driven from platform-codes.yaml
 20→ * - Template-based content generation
 21→ * - Multi-target installation support (e.g., GitHub Copilot)
 22→ * - Artifact type filtering (agents, workflows, tasks, tools)
 23→ */
 24→class ConfigDrivenIdeSetup extends BaseIdeSetup {
 25→  constructor(platformCode, platformConfig) {
 26→    super(platformCode, platformConfig.name, platformConfig.preferred);
 27→    this.platformConfig = platformConfig;
 28→    this.installerConfig = platformConfig.installer || null;
 29→
 30→    // Set configDir from target_dir so base-class detect() works
 31→    if (this.installerConfig?.target_dir) {
 32→      this.configDir = this.installerConfig.target_dir;
 33→    }
 34→  }
 35→
 36→  /**
 37→   * Detect whether this IDE already has configuration in the project.
 38→   * For skill_format platforms, checks for bmad-prefixed entries in target_dir
 39→   * (matching old codex.js behavior) instead of just checking directory existence.
 40→   * @param {string} projectDir - Project directory
 41→   * @returns {Promise<boolean>}
 42→   */
 43→  async detect(projectDir) {
 44→    if (this.installerConfig?.skill_format && this.configDir) {
 45→      const dir = path.join(projectDir || process.cwd(), this.configDir);
 46→      if (await fs.pathExists(dir)) {
 47→        try {
 48→          const entries = await fs.readdir(dir);
 49→          return entries.some((e) => typeof e === 'string' && e.startsWith('bmad'));
 50→        } catch {
 51→          return false;
 52→        }
 53→      }
 54→      return false;
 55→    }
 56→    return super.detect(projectDir);
 57→  }
 58→
 59→  /**
 60→   * Main setup method - called by IdeManager
 61→   * @param {string} projectDir - Project directory
 62→   * @param {string} bmadDir - BMAD installation directory
 63→   * @param {Object} options - Setup options
 64→   * @returns {Promise<Object>} Setup result
 65→   */
 66→  async setup(projectDir, bmadDir, options = {}) {
 67→    // Check for BMAD files in ancestor directories that would cause duplicates
 68→    if (this.installerConfig?.ancestor_conflict_check) {
 69→      const conflict = await this.findAncestorConflict(projectDir);
 70→      if (conflict) {
 71→        await prompts.log.error(
 72→          `Found existing BMAD skills in ancestor installation: ${conflict}\n` +
 73→            `  ${this.name} inherits skills from parent directories, so this would cause duplicates.\n` +
 74→            `  Please remove the BMAD files from that directory first:\n` +
 75→            `    rm -rf "${conflict}"/bmad*`,
 76→        );
 77→        return {
 78→          success: false,
 79→          reason: 'ancestor-conflict',
 80→          error: `Ancestor conflict: ${conflict}`,
 81→          conflictDir: conflict,
 82→        };
 83→      }
 84→    }
 85→
 86→    if (!options.silent) await prompts.log.info(`Setting up ${this.name}...`);
 87→
 88→    // Clean up any old BMAD installation first
 89→    await this.cleanup(projectDir, options);
 90→
 91→    if (!this.installerConfig) {
 92→      return { success: false, reason: 'no-config' };
 93→    }
 94→
 95→    // Handle multi-target installations (e.g., GitHub Copilot)
 96→    if (this.installerConfig.targets) {
 97→      return this.installToMultipleTargets(projectDir, bmadDir, this.installerConfig.targets, options);
 98→    }
 99→
100→    // Handle single-target installations
101→    if (this.installerConfig.target_dir) {
102→      return this.installToTarget(projectDir, bmadDir, this.installerConfig, options);
