 14→  if (_cachedPlatformCodes) {
 15→    return _cachedPlatformCodes;
 16→  }
 17→
 18→  if (!(await fs.pathExists(PLATFORM_CODES_PATH))) {
 19→    throw new Error(`Platform codes configuration not found at: ${PLATFORM_CODES_PATH}`);
 20→  }
