 30→ * @returns {Object|null} Platform info or null if not found
 31→ */
 32→function getPlatformInfo(platformCode) {
 33→  if (!_cachedPlatformCodes) {
 34→    throw new Error('Platform codes not loaded. Call loadPlatformCodes() first.');
