  1→/**
  2→ * Path transformation utilities for IDE installer standardization
  3→ *
  4→ * Provides utilities to convert hierarchical paths to flat naming conventions.
  5→ *
  6→ * DASH-BASED NAMING (new standard):
  7→ * - Agents: bmad-agent-module-name.md (with bmad-agent- prefix)
  8→ * - Workflows/Tasks/Tools: bmad-module-name.md
  9→ *
 10→ * Example outputs:
 11→ * - cis/agents/storymaster.md → bmad-agent-cis-storymaster.md
 12→ * - bmm/workflows/plan-project.md → bmad-bmm-plan-project.md
 13→ * - bmm/tasks/create-story.md → bmad-bmm-create-story.md
 14→ * - core/agents/brainstorming.md → bmad-agent-brainstorming.md (core agents skip module name)
 15→ */
 16→
 17→// Type segments - agents are included in naming, others are filtered out
 18→const TYPE_SEGMENTS = ['workflows', 'tasks', 'tools'];
 19→const AGENT_SEGMENT = 'agents';
 20→
 21→// BMAD installation folder name - centralized constant for all installers
 22→const BMAD_FOLDER_NAME = '_bmad';
 23→
 24→/**
 25→ * Convert hierarchical path to flat dash-separated name (NEW STANDARD)
 26→ * Converts: 'bmm', 'agents', 'pm' → 'bmad-agent-bmm-pm.md'
 27→ * Converts: 'bmm', 'workflows', 'correct-course' → 'bmad-bmm-correct-course.md'
 28→ * Converts: 'core', 'agents', 'brainstorming' → 'bmad-agent-brainstorming.md' (core agents skip module name)
 29→ *
 30→ * @param {string} module - Module name (e.g., 'bmm', 'core')
 31→ * @param {string} type - Artifact type ('agents', 'workflows', 'tasks', 'tools')
 32→ * @param {string} name - Artifact name (e.g., 'pm', 'brainstorming')
 33→ * @returns {string} Flat filename like 'bmad-agent-bmm-pm.md' or 'bmad-bmm-correct-course.md'
 34→ */
 35→function toDashName(module, type, name) {
 36→  const isAgent = type === AGENT_SEGMENT;
 37→
 38→  // For core module, skip the module name: use 'bmad-agent-name.md' instead of 'bmad-agent-core-name.md'
 39→  if (module === 'core') {
 40→    return isAgent ? `bmad-agent-${name}.md` : `bmad-${name}.md`;
 41→  }
 42→
 43→  // Module artifacts: bmad-module-name.md or bmad-agent-module-name.md
 44→  // eslint-disable-next-line unicorn/prefer-string-replace-all -- regex replace is intentional here
 45→  const dashName = name.replace(/\//g, '-'); // Flatten nested paths
 46→  return isAgent ? `bmad-agent-${module}-${dashName}.md` : `bmad-${module}-${dashName}.md`;
 47→}
 48→
 49→/**
 50→ * Convert relative path to flat dash-separated name
 51→ * Converts: 'bmm/agents/pm.md' → 'bmad-agent-bmm-pm.md'
 52→ * Converts: 'bmm/agents/tech-writer/tech-writer.md' → 'bmad-agent-bmm-tech-writer.md' (uses folder name)
 53→ * Converts: 'bmm/workflows/correct-course.md' → 'bmad-bmm-correct-course.md'
 54→ * Converts: 'core/agents/brainstorming.md' → 'bmad-agent-brainstorming.md' (core agents skip module name)
 55→ *
 56→ * @param {string} relativePath - Path like 'bmm/agents/pm.md'
 57→ * @returns {string} Flat filename like 'bmad-agent-bmm-pm.md' or 'bmad-brainstorming.md'
 58→ */
 59→function toDashPath(relativePath) {
 60→  if (!relativePath || typeof relativePath !== 'string') {
 61→    // Return a safe default for invalid input
 62→    return 'bmad-unknown.md';
 63→  }
 64→
 65→  // Strip common file extensions to avoid double extensions in generated filenames
 66→  // e.g., 'create-story.xml' → 'create-story', 'workflow.yaml' → 'workflow'
 67→  const withoutExt = relativePath.replace(/\.(md|yaml|yml|json|xml|toml)$/i, '');
 68→  const parts = withoutExt.split(/[/\\]/);
 69→
 70→  const module = parts[0];
 71→  const type = parts[1];
 72→  let name;
 73→
 74→  // For agents, if nested in a folder (more than 3 parts), use the folder name only
 75→  // e.g., 'bmm/agents/tech-writer/tech-writer' → 'tech-writer' (not 'tech-writer-tech-writer')
 76→  if (type === 'agents' && parts.length > 3) {
 77→    // Use the folder name (parts[2]) as the name, ignore the file name
 78→    name = parts[2];
 79→  } else {
 80→    // For non-nested or non-agents, join all parts after type
 81→    name = parts.slice(2).join('-');
 82→  }
 83→
 84→  return toDashName(module, type, name);
 85→}
