 87→/**
 88→ * Create custom agent dash name
 89→ * Creates: 'bmad-custom-agent-fred-commit-poet.md'
 90→ *
 91→ * @param {string} agentName - Custom agent name
 92→ * @returns {string} Flat filename like 'bmad-custom-agent-fred-commit-poet.md'
 93→ */
 94→function customAgentDashName(agentName) {
 95→  return `bmad-custom-agent-${agentName}.md`;
 96→}
 97→
 98→/**
 99→ * Check if a filename uses dash format
100→ * @param {string} filename - Filename to check
101→ * @returns {boolean} True if filename uses dash format
102→ */
103→function isDashFormat(filename) {
104→  return filename.startsWith('bmad-') && filename.includes('-');
105→}
106→
107→/**
108→ * Extract parts from a dash-formatted filename
109→ * Parses: 'bmad-agent-bmm-pm.md' → { prefix: 'bmad', module: 'bmm', type: 'agents', name: 'pm' }
110→ * Parses: 'bmad-bmm-correct-course.md' → { prefix: 'bmad', module: 'bmm', type: 'workflows', name: 'correct-course' }
111→ * Parses: 'bmad-agent-brainstorming.md' → { prefix: 'bmad', module: 'core', type: 'agents', name: 'brainstorming' } (core agents)
112→ * Parses: 'bmad-brainstorming.md' → { prefix: 'bmad', module: 'core', type: 'workflows', name: 'brainstorming' } (core workflows)
113→ *
114→ * @param {string} filename - Dash-formatted filename
115→ * @returns {Object|null} Parsed parts or null if invalid format
116→ */
117→function parseDashName(filename) {
118→  const withoutExt = filename.replace('.md', '');
119→  const parts = withoutExt.split('-');
120→
121→  if (parts.length < 2 || parts[0] !== 'bmad') {
122→    return null;
123→  }
124→
125→  // Check if this is an agent file (has 'agent' as second part)
126→  const isAgent = parts[1] === 'agent';
127→
128→  if (isAgent) {
129→    // This is an agent file
130→    // Format: bmad-agent-name (core) or bmad-agent-module-name
131→    if (parts.length === 3) {
132→      // Core agent: bmad-agent-name
133→      return {
134→        prefix: parts[0],
135→        module: 'core',
136→        type: 'agents',
137→        name: parts[2],
138→      };
139→    } else {
140→      // Module agent: bmad-agent-module-name
141→      return {
142→        prefix: parts[0],
143→        module: parts[2],
144→        type: 'agents',
145→        name: parts.slice(3).join('-'),
146→      };
147→    }
148→  }
149→
150→  // Not an agent file - must be a workflow/tool/task
151→  // If only 2 parts (bmad-name), it's a core workflow/tool/task
152→  if (parts.length === 2) {
153→    return {
154→      prefix: parts[0],
155→      module: 'core',
156→      type: 'workflows', // Default to workflows for non-agent core items
157→      name: parts[1],
158→    };
159→  }
160→
161→  // Otherwise, it's a module workflow/tool/task (bmad-module-name)
162→  return {
163→    prefix: parts[0],
164→    module: parts[1],
165→    type: 'workflows', // Default to workflows for non-agent module items
166→    name: parts.slice(2).join('-'),
167→  };
168→}
