17→
18→  // Get module agents
19→  for (const moduleName of selectedModules) {
20→    const agentsPath = path.join(bmadDir, moduleName, 'agents');
21→
22→    if (await fs.pathExists(agentsPath)) {
23→      const moduleAgents = await getAgentsFromDir(agentsPath, moduleName);
24→      agents.push(...moduleAgents);
25→    }
26→  }
27→
28→  // Get standalone agents from bmad/agents/ directory
29→  const standaloneAgentsDir = path.join(bmadDir, 'agents');
30→  if (await fs.pathExists(standaloneAgentsDir)) {
31→    const agentDirs = await fs.readdir(standaloneAgentsDir, { withFileTypes: true });
32→
33→    for (const agentDir of agentDirs) {
34→      if (!agentDir.isDirectory()) continue;
35→
36→      const agentDirPath = path.join(standaloneAgentsDir, agentDir.name);
37→      const agentFiles = await fs.readdir(agentDirPath);
38→      const skillManifest = await loadSkillManifest(agentDirPath);
39→
40→      for (const file of agentFiles) {
41→        if (!file.endsWith('.md')) continue;
42→        if (file.includes('.customize.')) continue;
43→
44→        const filePath = path.join(agentDirPath, file);
45→        const content = await fs.readFile(filePath, 'utf8');
46→
47→        if (content.includes('localskip="true"')) continue;
48→
49→        agents.push({
50→          path: filePath,
51→          name: file.replace('.md', ''),
52→          module: 'standalone', // Mark as standalone agent
53→          canonicalId: getCanonicalId(skillManifest, file),
