          if (!config.forge_data_folder && savedData.forge_data_folder) config.forge_data_folder = savedData.forge_data_folder;
        } catch {
          /* ignore parse errors, defaults will apply */
        }
      }

      const removeSpinner = ora('Updating SKF files...').start();
