 54→        process.exit(1);
 55→      }
 56→
 57→      const { bmadDir } = await installer.findBmadDir(projectDir);
 58→
 59→      if (!(await fs.pathExists(bmadDir))) {
 60→        await prompts.log.warn('No BMAD installation found.');
 61→        process.exit(0);
 62→      }
 63→
 64→      const existingInstall = await installer.getStatus(projectDir);
 65→      const version = existingInstall.version || 'unknown';
 66→      const modules = (existingInstall.modules || []).map((m) => m.id || m.name).join(', ');
 67→      const ides = (existingInstall.ides || []).join(', ');
 68→
 69→      const outputFolder = await installer.getOutputFolder(projectDir);
 70→
 71→      await prompts.intro('BMAD Uninstall');
 72→      await prompts.note(`Version: ${version}\nModules: ${modules}\nIDE integrations: ${ides}`, 'Current Installation');
 73→
 74→      let removeModules = true;
 75→      let removeIdeConfigs = true;
 76→      let removeOutputFolder = false;
 77→
 78→      if (!options.yes) {
 79→        // multiselect() handles cancellation internally (exits process)
 80→        const selected = await prompts.multiselect({
 81→          message: 'Select components to remove:',
 82→          options: [
 83→            {
 84→              value: 'modules',
 85→              label: `BMAD Modules & data (${installer.bmadFolderName}/)`,
 86→              hint: 'Core installation, agents, workflows, config',
 87→            },
 88→            { value: 'ide', label: 'IDE integrations', hint: ides || 'No IDEs configured' },
 89→            { value: 'output', label: `User artifacts (${outputFolder}/)`, hint: 'WARNING: Contains your work products' },
 90→          ],
 91→          initialValues: ['modules', 'ide'],
 92→          required: true,
 93→        });
 94→
 95→        removeModules = selected.includes('modules');
 96→        removeIdeConfigs = selected.includes('ide');
 97→        removeOutputFolder = selected.includes('output');
 98→
 99→        const red = (s) => `\u001B[31m${s}\u001B[0m`;
100→        await prompts.note(
101→          red('💀 This action is IRREVERSIBLE! Removed files cannot be recovered!') +
102→            '\n' +
103→            red('💀 IDE configurations and modules will need to be reinstalled.') +
104→            '\n' +
105→            red('💀 User artifacts are preserved unless explicitly selected.'),
106→          '!! DESTRUCTIVE ACTION !!',
107→        );
108→
109→        const confirmed = await prompts.confirm({
110→          message: 'Proceed with uninstall?',
111→          default: false,
112→        });
113→
114→        if (!confirmed) {
115→          await prompts.outro('Uninstall cancelled.');
116→          process.exit(0);
117→        }
118→      }
119→
120→      // Phase 1: IDE integrations
121→      if (removeIdeConfigs) {
122→        const s = await prompts.spinner();
123→        s.start('Removing IDE integrations...');
124→        await installer.uninstallIdeConfigs(projectDir, existingInstall, { silent: true });
125→        s.stop(`Removed IDE integrations (${ides || 'none'})`);
126→      }
127→
128→      // Phase 2: User artifacts
129→      if (removeOutputFolder) {
130→        const s = await prompts.spinner();
131→        s.start(`Removing user artifacts (${outputFolder}/)...`);
132→        await installer.uninstallOutputFolder(projectDir, outputFolder);
133→        s.stop('User artifacts removed');
134→      }
135→
136→      // Phase 3: BMAD modules & data (last — other phases may need _bmad/)
137→      if (removeModules) {
138→        const s = await prompts.spinner();
139→        s.start(`Removing BMAD modules & data (${installer.bmadFolderName}/)...`);
140→        await installer.uninstallModules(projectDir);
141→        s.stop('Modules & data removed');
142→      }
143→
144→      const summary = [];
145→      if (removeIdeConfigs) summary.push('IDE integrations cleaned');
146→      if (removeModules) summary.push('Modules & data removed');
147→      if (removeOutputFolder) summary.push('User artifacts removed');
148→      if (!removeOutputFolder) summary.push(`User artifacts preserved in ${outputFolder}/`);
149→
150→      await prompts.note(summary.join('\n'), 'Summary');
151→      await prompts.outro('To reinstall, run: npx bmad-method install');
152→
153→      process.exit(0);
154→    } catch (error) {
155→      try {
156→        const errorMessage = error instanceof Error ? error.message : String(error);
157→        await prompts.log.error(`Uninstall failed: ${errorMessage}`);
158→        if (error instanceof Error && error.stack) {
159→          await prompts.log.message(error.stack);
160→        }
161→      } catch {
162→        console.error(error instanceof Error ? error.message : error);
163→      }
164→      process.exit(1);
165→    }
166→  },
