 21→  /**
 22→   * Set the bmad folder name for all IDE handlers
 23→   * @param {string} bmadFolderName - The bmad folder name
 24→   */
 25→  setBmadFolderName(bmadFolderName) {
 26→    this.bmadFolderName = bmadFolderName;
 27→    // Update all loaded handlers
 28→    for (const handler of this.handlers.values()) {
 29→      if (typeof handler.setBmadFolderName === 'function') {
 30→        handler.setBmadFolderName(bmadFolderName);
 31→      }
 32→    }
 33→  }
 34→
 35→  /**
 36→   * Ensure handlers are loaded (lazy loading)
 37→   */
 38→  async ensureInitialized() {
 39→    if (!this._initialized) {
 40→      await this.loadHandlers();
 41→      this._initialized = true;
 42→    }
 43→  }
 44→
 45→  /**
 46→   * Dynamically load all IDE handlers
 47→   * 1. Load custom installer files first (github-copilot.js, kilo.js, rovodev.js)
 48→   * 2. Load config-driven handlers from platform-codes.yaml
 49→   */
 50→  async loadHandlers() {
 51→    // Load custom installer files
 52→    await this.loadCustomInstallerFiles();
 53→
 54→    // Load config-driven handlers from platform-codes.yaml
 55→    await this.loadConfigDrivenHandlers();
 56→  }
 57→
 58→  /**
 59→   * Load custom installer files (unique installation logic)
 60→   * These files have special installation patterns that don't fit the config-driven model
 61→   * Note: codex was migrated to config-driven (platform-codes.yaml) and no longer needs a custom installer
 62→   */
 63→  async loadCustomInstallerFiles() {
 64→    const ideDir = __dirname;
 65→    const customFiles = ['github-copilot.js', 'kilo.js', 'rovodev.js'];
 66→
 67→    for (const file of customFiles) {
 68→      const filePath = path.join(ideDir, file);
 69→      if (!fs.existsSync(filePath)) continue;
 70→
 71→      try {
 72→        const HandlerModule = require(filePath);
 73→        const HandlerClass = HandlerModule.default || Object.values(HandlerModule)[0];
 74→
 75→        if (HandlerClass) {
 76→          const instance = new HandlerClass();
 77→          if (instance.name && typeof instance.name === 'string') {
 78→            if (typeof instance.setBmadFolderName === 'function') {
 79→              instance.setBmadFolderName(this.bmadFolderName);
 80→            }
 81→            this.handlers.set(instance.name, instance);
 82→          }
 83→        }
 84→      } catch (error) {
