 99→
100→    for (const [platformCode, platformInfo] of Object.entries(platformConfig.platforms)) {
101→      // Skip if already loaded by custom installer
102→      if (this.handlers.has(platformCode)) continue;
103→
104→      // Skip if no installer config (platform may not need installation)
105→      if (!platformInfo.installer) continue;
106→
107→      const handler = new ConfigDrivenIdeSetup(platformCode, platformInfo);
108→      if (typeof handler.setBmadFolderName === 'function') {
