122→    for (const [key, handler] of this.handlers) {
123→      // Skip handlers without valid names
124→      const name = handler.displayName || handler.name || key;
125→
126→      // Filter out invalid entries (undefined name, empty key, etc.)
127→      if (!key || !name || typeof key !== 'string' || typeof name !== 'string') {
128→        continue;
129→      }
130→
131→      ides.push({
132→        value: key,
133→        name: name,
134→        preferred: handler.preferred || false,
135→      });
136→    }
137→
138→    // Sort: preferred first, then alphabetical
139→    ides.sort((a, b) => {
140→      if (a.preferred && !b.preferred) return -1;
141→      if (!a.preferred && b.preferred) return 1;
142→      return a.name.localeCompare(b.name);
143→    });
144→
145→    return ides;
146→  }
