169→   * @param {Object} options - Setup options
170→   */
171→  async setup(ideName, projectDir, bmadDir, options = {}) {
172→    const handler = this.handlers.get(ideName.toLowerCase());
173→
174→    if (!handler) {
175→      await prompts.log.warn(`IDE '${ideName}' is not yet supported`);
176→      await prompts.log.message(`Supported IDEs: ${[...this.handlers.keys()].join(', ')}`);
177→      return { success: false, ide: ideName, error: 'unsupported IDE' };
178→    }
179→
180→    try {
181→      const handlerResult = await handler.setup(projectDir, bmadDir, options);
182→      // Build detail string from handler-returned data
183→      let detail = '';
184→      if (handlerResult && handlerResult.results) {
185→        // Config-driven handlers return { success, results: { agents, workflows, tasks, tools } }
186→        const r = handlerResult.results;
187→        const parts = [];
188→        if (r.agents > 0) parts.push(`${r.agents} agents`);
189→        if (r.workflows > 0) parts.push(`${r.workflows} workflows`);
190→        if (r.tasks > 0) parts.push(`${r.tasks} tasks`);
191→        if (r.tools > 0) parts.push(`${r.tools} tools`);
192→        detail = parts.join(', ');
193→      } else if (handlerResult && handlerResult.modes !== undefined) {
194→        // Kilo handler returns { success, modes, workflows, tasks, tools }
195→        const parts = [];
196→        if (handlerResult.modes > 0) parts.push(`${handlerResult.modes} modes`);
197→        if (handlerResult.workflows > 0) parts.push(`${handlerResult.workflows} workflows`);
198→        if (handlerResult.tasks > 0) parts.push(`${handlerResult.tasks} tasks`);
199→        if (handlerResult.tools > 0) parts.push(`${handlerResult.tools} tools`);
200→        detail = parts.join(', ');
201→      }
202→      // Propagate handler's success status (default true for backward compat)
203→      const success = handlerResult?.success !== false;
204→      return { success, ide: ideName, detail, error: handlerResult?.error, handlerResult };
205→    } catch (error) {
206→      await prompts.log.error(`Failed to setup ${ideName}: ${error.message}`);
207→      return { success: false, ide: ideName, error: error.message };
208→    }
