222→        results.push({ ide: name, success: true });
223→      } catch (error) {
224→        results.push({ ide: name, success: false, error: error.message });
225→      }
226→    }
227→
228→    return results;
229→  }
230→
231→  /**
232→   * Cleanup only the IDEs in the provided list
233→   * Falls back to cleanup() (all handlers) if ideList is empty or undefined
234→   * @param {string} projectDir - Project directory
235→   * @param {Array<string>} ideList - List of IDE names to clean up
236→   * @param {Object} [options] - Cleanup options passed through to handlers
237→   * @returns {Array} Results array
238→   */
239→  async cleanupByList(projectDir, ideList, options = {}) {
240→    if (!ideList || ideList.length === 0) {
241→      return this.cleanup(projectDir, options);
242→    }
243→
244→    await this.ensureInitialized();
245→    const results = [];
246→
247→    // Build lowercase lookup for case-insensitive matching
248→    const lowercaseHandlers = new Map([...this.handlers.entries()].map(([k, v]) => [k.toLowerCase(), v]));
249→
250→    for (const ideName of ideList) {
251→      const handler = lowercaseHandlers.get(ideName.toLowerCase());
252→      if (!handler) continue;
253→
254→      try {
255→        await handler.cleanup(projectDir, options);
256→        results.push({ ide: ideName, success: true });
257→      } catch (error) {
258→        results.push({ ide: ideName, success: false, error: error.message });
259→      }
260→    }
261→
262→    return results;
263→  }
264→
265→  /**
266→   * Get list of supported IDEs
267→   * @returns {Array} List of supported IDE names
268→   */
269→  getSupportedIdes() {
270→    return [...this.handlers.keys()];
271→  }
272→
273→  /**
274→   * Check if an IDE is supported
275→   * @param {string} ideName - Name of the IDE
276→   * @returns {boolean} True if IDE is supported
277→   */
278→  isSupported(ideName) {
279→    return this.handlers.has(ideName.toLowerCase());
280→  }
281→
282→  /**
283→   * Detect installed IDEs
284→   * @param {string} projectDir - Project directory
285→   * @returns {Array} List of detected IDEs
286→   */
287→  async detectInstalledIdes(projectDir) {
288→    const detected = [];
289→
290→    for (const [name, handler] of this.handlers) {
291→      if (typeof handler.detect === 'function' && (await handler.detect(projectDir))) {
292→        detected.push(name);
293→      }
294→    }
295→
296→    return detected;
297→  }
298→
299→  /**
300→   * Install custom agent launchers for specified IDEs
301→   * @param {Array} ides - List of IDE names to install for
302→   * @param {string} projectDir - Project directory
303→   * @param {string} agentName - Agent name (e.g., "fred-commit-poet")
304→   * @param {string} agentPath - Path to compiled agent (relative to project root)
305→   * @param {Object} metadata - Agent metadata
306→   * @returns {Object} Results for each IDE
307→   */
308→  async installCustomAgentLaunchers(ides, projectDir, agentName, agentPath, metadata) {
309→    const results = {};
310→
311→    for (const ideName of ides) {
312→      const handler = this.handlers.get(ideName.toLowerCase());
313→
314→      if (!handler) {
315→        await prompts.log.warn(`IDE '${ideName}' is not yet supported for custom agent installation`);
316→        continue;
317→      }
318→
319→      try {
320→        if (typeof handler.installCustomAgentLauncher === 'function') {
321→          const result = await handler.installCustomAgentLauncher(projectDir, agentName, agentPath, metadata);
322→          if (result) {
323→            results[ideName] = result;
324→          }
325→        }
326→      } catch (error) {
327→        await prompts.log.warn(`Failed to install ${ideName} launcher: ${error.message}`);
328→      }
329→    }
330→
331→    return results;
332→  }
333→}
