145→/**
146→ * Remove SKF-related command files from an IDE target directory.
147→ * Only removes files matching the bmad-skf-* and bmad-agent-skf-* patterns.
148→ */
149→async function cleanSkfCommands(targetDir) {
150→  if (!(await fs.pathExists(targetDir))) return 0;
151→
152→  const files = await fs.readdir(targetDir);
153→  let removed = 0;
154→  for (const file of files) {
155→    if (file.startsWith('bmad-skf-') || file.startsWith('bmad-agent-skf-')) {
156→      await fs.remove(path.join(targetDir, file));
157→      removed++;
158→    }
159→  }
160→
161→  // Remove empty parent directories (e.g. .cursor/commands/ then .cursor/)
162→  if (removed > 0) {
163→    const remaining = await fs.readdir(targetDir);
164→    if (remaining.length === 0) {
165→      await fs.remove(targetDir);
166→      const parentDir = path.dirname(targetDir);
167→      const parentRemaining = await fs.readdir(parentDir);
168→      if (parentRemaining.length === 0) {
169→        await fs.remove(parentDir);
170→      }
171→    }
172→  }
173→
174→  return removed;
175→}
