188→/**
189→ * Generate IDE command files for all selected IDEs.
190→ *
191→ * @param {string} projectDir - Project root directory
192→ * @param {string} skfFolder - Relative path to SKF dir (e.g. '_bmad/skf')
193→ * @param {string[]} ides - Array of IDE codes (e.g. ['claude-code', 'cursor'])
194→ * @returns {{ generated: number, ides: string[] }}
195→ */
196→async function generateIdeCommands(projectDir, skfFolder, ides) {
197→  // Always clean old SKF commands from all IDEs first
198→  await cleanAllSkfCommands(projectDir);
199→
200→  if (!ides || ides.length === 0) return { generated: 0, ides: [] };
201→
202→  const skfDir = path.join(projectDir, skfFolder);
203→  const moduleCode = 'skf';
204→
205→  // Collect artifacts
206→  const agents = await collectAgents(skfDir, skfFolder);
207→  const workflows = await collectWorkflows(skfDir, skfFolder);
208→
209→  let totalGenerated = 0;
210→  const processedIdes = [];
211→
212→  for (const ide of ides) {
213→    const targetRelDir = IDE_TARGETS[ide];
214→    if (!targetRelDir) continue; // Skip unknown IDEs (e.g. 'other')
215→
216→    const targetDir = path.join(projectDir, targetRelDir);
217→    await fs.ensureDir(targetDir);
218→
219→    // Generate agent commands
220→    for (const agent of agents) {
221→      const fileName = `bmad-agent-${moduleCode}-${agent.name}.md`;
222→      const content = renderAgentCommand(agent.name, agent.description, agent.relativePath);
223→      await fs.writeFile(path.join(targetDir, fileName), content, 'utf8');
224→      totalGenerated++;
225→    }
226→
227→    // Generate workflow commands
228→    for (const workflow of workflows) {
229→      const fileName = `bmad-${moduleCode}-${workflow.name}.md`;
230→      const content = renderWorkflowCommand(workflow.description, workflow.relativePath);
231→      await fs.writeFile(path.join(targetDir, fileName), content, 'utf8');
232→      totalGenerated++;
233→    }
234→
235→    processedIdes.push(ide);
236→  }
237→
238→  return { generated: totalGenerated, ides: processedIdes };
239→}
